"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[3606],{76339:(e,n,i)=>{i.r(n),i.d(n,{data:()=>s});const s={key:"v-567dbef0",path:"/C#/%E8%87%AA%E5%AE%9A%E4%B9%89%E6%8E%A7%E4%BB%B6/10.%E6%95%B0%E6%8D%AE%E5%9B%9E%E4%BC%A0IPostBackDataHandler.html",title:"自定义控件(十)-数据回传IPostBackDataHandler",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[],git:{updatedTime:1655779244e3,contributors:[{name:"panzhiyue",email:"30484534+panzhiyue@users.noreply.github.com",commits:1}]},filePathRelative:"C#/自定义控件/10.数据回传IPostBackDataHandler.md"}},4039:(e,n,i)=>{i.r(n),i.d(n,{default:()=>a});const s=(0,i(57293).uE)('<h1 id="自定义控件-十-数据回传ipostbackdatahandler" tabindex="-1"><a class="header-anchor" href="#自定义控件-十-数据回传ipostbackdatahandler" aria-hidden="true">#</a> 自定义控件(十)-数据回传IPostBackDataHandler</h1><p>所有实现了IPostBackDataHandler接口的控件都获得了从回传表单中获取心值的机会。</p><p>IpostBackDataHandler需要实现两个方法</p><p>(1)LoadPostData() 处理页面交过来的回传数据</p><p>(2)RaisePostDataChangedEvent() 如果LoadPostData()方法返回true,则此方法被调用,此方法通常用来触发控件的事件。</p><p>下面实现一个例子</p><p>控件代码</p><div class="language-csharp ext-cs line-numbers-mode"><pre class="language-csharp"><code>using System;\nusing System.ComponentModel;\nusing System.Web;\nusing System.Web.UI;\nusing System.Web.UI.WebControls;\n\nnamespace kjlx.BLL.IPostBack\n{\n\n    [ParseChildren(true, &quot;Text&quot;)]    //把控件内容设置为Text属性\n    [DefaultProperty(&quot;Text&quot;),        //查看控件属性时，焦点为Text属性\n    DefaultEvent(&quot;TextChanged&quot;)]     //默认事件为TextChanged\n    public class IPostBackTest1 : WebControl, IPostBackDataHandler\n    {\n        private static object TextChangeEvent = new object();   //定义TextChangeEvent\n        protected override HtmlTextWriterTag TagKey\n        {\n            get { return HtmlTextWriterTag.Textarea; }\n        }\n        //Text属性\n        [Category(&quot;Appearance&quot;),                                          //外观\n        PersistenceMode(PersistenceMode.EncodedInnerDefaultProperty),        //指定属性保存为控件的唯一内容，当属性为字符串类型而且是HTML编码时可以使用此值\n        DefaultValue(&quot;&quot;)]                                                    //默认值为&quot;&quot;\n        public virtual string Text\n        {\n            get\n            {\n                if (ViewState[&quot;Text&quot;] != null)\n                {\n                    return (string)ViewState[&quot;Text&quot;];\n                }\n                return string.Empty;\n            }\n            set { ViewState[&quot;Text&quot;] = value; }\n        }\n        /// &lt;summary&gt;\n        /// 声明事件\n        /// &lt;/summary&gt;\n        [Category(&quot;Action&quot;)]        //行为\n        public event EventHandler myTextChanged\n        {\n            add\n            {\n                Events.AddHandler(TextChangeEvent, value);\n            }\n            remove\n            {\n                Events.RemoveHandler(TextChangeEvent, value);\n            }\n        }\n        /// &lt;summary&gt;\n        /// 给TextArea添加属性，如name是回传必须的属性\n        /// &lt;/summary&gt;\n        /// &lt;param name=&quot;writer&quot;&gt;&lt;/param&gt;\n        protected override void AddAttributesToRender(System.Web.UI.HtmlTextWriter writer)\n        {\n            base.AddAttributesToRender(writer);\n            if (Page != null)\n            {\n                Page.VerifyRenderingInServerForm(this);      //确保控件放置在HtmlForm控件中\n            }\n            writer.AddAttribute(HtmlTextWriterAttribute.Name, this.UniqueID);  //把UniqueID设置为控件的name属性,因为表单回传时需要用到name\n\n            if (!Enabled)\n            {\n                writer.AddAttribute(HtmlTextWriterAttribute.Disabled, &quot;disabled&quot;);\n            }\n        }\n\n       \n        /// &lt;summary&gt;\n        /// 处理页面交过来的回传数据\n        /// &lt;/summary&gt;\n        /// &lt;param name=&quot;postDataKey&quot;&gt;回传数据在在回传表单时的键&lt;/param&gt;\n        /// &lt;param name=&quot;postCollection&quot;&gt;回传表单中的所有值的集合&lt;/param&gt;\n        /// &lt;returns&gt;&lt;/returns&gt;\n        public bool LoadPostData(string postDataKey, System.Collections.Specialized.NameValueCollection postCollection)\n        {\n            \n            string text = this.Text;\n            string text2 = postCollection[postDataKey];\n            if (!text.Equals(text2, StringComparison.Ordinal))\n            {\n                this.Text = text2;\n                return true;\n            }\n            return false;\n\n        }\n        /// &lt;summary&gt;\n        /// 给控件添加内容，否则回传后结果会清空\n        /// &lt;/summary&gt;\n        /// &lt;param name=&quot;writer&quot;&gt;&lt;/param&gt;\n        protected override void RenderContents(HtmlTextWriter writer)\n        {\n            //把html变为文本\n            HttpUtility.HtmlEncode(this.Text, writer);\n        }\n        /// &lt;summary&gt;\n        /// 如果LoadPostData()方法返回true,则次方法将被调用，次方法通常用来触发控件的事件\n        /// &lt;/summary&gt;\n        public void RaisePostDataChangedEvent()\n        {\n            EventHandler handler = (EventHandler)Events[TextChangeEvent];\n            if (handler != null)\n            {\n                handler(this, EventArgs.Empty);\n            }\n        }\n    }\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><p>html代码</p><div class="language-csharp ext-cs line-numbers-mode"><pre class="language-csharp"><code>    &lt;cc1:IPostBackTest1 ID=&quot;IPostBackTest1&quot; runat=&quot;server&quot; \n        ontextchanged=&quot;IPostBackTest1_myTextChanged&quot; &gt;&lt;/cc1:IPostBackTest1&gt;\n        &lt;asp:Button ID=&quot;Button1&quot; runat=&quot;server&quot; Text=&quot;Button&quot; /&gt;\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><p>后台代码</p><div class="language-csharp ext-cs line-numbers-mode"><pre class="language-csharp"><code>    protected void IPostBackTest1_myTextChanged(object sender, EventArgs e)\n    {\n        Response.Write(IPostBackTest1.Text);\n    }\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><p>实现功能:在页面上定义一个TextArea,如果TextArea内容改变,页面提交后在网页上输出TextArea的内容。TextArea没有提交页面的功能，所有添加Button用于提交页面。</p><p>显示结果</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202206210854312.png" alt="img"><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"> 下面对代码进行分析</p><div class="language-csharp ext-cs line-numbers-mode"><pre class="language-csharp"><code>private static object TextChangeEvent = new object();   //定义TextChangeEvent\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><p>相当于定义了一个事件的键</p><div class="language-csharp ext-cs line-numbers-mode"><pre class="language-csharp"><code> /// &lt;summary&gt;\n        /// 声明事件\n        /// &lt;/summary&gt;\n        [Category(&quot;Action&quot;)]        //行为\n        public event EventHandler myTextChanged\n        {\n            add\n            {\n                Events.AddHandler(TextChangeEvent, value);\n            }\n            remove\n            {\n                Events.RemoveHandler(TextChangeEvent, value);\n            }\n        }\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><p>以上代码定义了myTextChanged事件属性</p><p>在后台定义了myTextChanged事件属性后，后把事件添加到Events集合中,根据键进行存取</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202206210854313.png" alt="img"><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><p>Events是一个事件集合，根据键进行存取，像之前定义的myTextChanged</p><p>Events.AddHandler(TextChangeEvent,value); TextChangeEvent是键,value是事件属性值 也可以写成Events[TextChangeEvent]=value</p><div class="language-csharp ext-cs line-numbers-mode"><pre class="language-csharp"><code>       /// &lt;summary&gt;\n        /// 给TextArea添加属性，如name是回传必须的属性\n        /// &lt;/summary&gt;\n        /// &lt;param name=&quot;writer&quot;&gt;&lt;/param&gt;\n        protected override void AddAttributesToRender(System.Web.UI.HtmlTextWriter writer)\n        {\n            base.AddAttributesToRender(writer);\n            if (Page != null)\n            {\n                Page.VerifyRenderingInServerForm(this);      //确保控件放置在HtmlForm控件中\n            }\n            writer.AddAttribute(HtmlTextWriterAttribute.Name, this.UniqueID);  //把UniqueID设置为控件的name属性,因为表单回传时需要用到name\n\n            if (!Enabled)\n            {\n                writer.AddAttribute(HtmlTextWriterAttribute.Disabled, &quot;disabled&quot;);\n            }\n        }\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><p>要回传的控件必须包含在Form中，要有name值</p><div class="language-csharp ext-cs line-numbers-mode"><pre class="language-csharp"><code> /// &lt;summary&gt;\n        /// 处理页面交过来的回传数据\n        /// &lt;/summary&gt;\n        /// &lt;param name=&quot;postDataKey&quot;&gt;回传数据在在回传表单时的键&lt;/param&gt;\n        /// &lt;param name=&quot;postCollection&quot;&gt;回传表单中的所有值的集合&lt;/param&gt;\n        /// &lt;returns&gt;&lt;/returns&gt;\n        public bool LoadPostData(string postDataKey, System.Collections.Specialized.NameValueCollection postCollection)\n        {\n            \n            string text = this.Text;\n            string text2 = postCollection[postDataKey];\n            if (!text.Equals(text2, StringComparison.Ordinal))\n            {\n                this.Text = text2;\n                return true;\n            }\n            return false;\n\n        }\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><p>以上方法是对页面回传数据进行处理</p><p>首先对比值是否改变，如果是就把新值赋给Text,并执行RaisePostDataChangedEvent</p><div class="language-csharp ext-cs line-numbers-mode"><pre class="language-csharp"><code>        /// &lt;summary&gt;\n        /// 给控件添加内容，否则回传后结果会清空\n        /// &lt;/summary&gt;\n        /// &lt;param name=&quot;writer&quot;&gt;&lt;/param&gt;\n        protected override void RenderContents(HtmlTextWriter writer)\n        {\n            //把html变为文本\n            HttpUtility.HtmlEncode(this.Text, writer);\n        }\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>把Text作为控件的内容，否则你会发现控件内容始终为空</p><p>从这也可以看出，RenderContents是在LoadPostData方法之后执行</p><div class="language-csharp ext-cs line-numbers-mode"><pre class="language-csharp"><code> /// &lt;summary&gt;\n        /// 如果LoadPostData()方法返回true,则次方法将被调用，次方法通常用来触发控件的事件\n        /// &lt;/summary&gt;\n        public void RaisePostDataChangedEvent()\n        {\n            EventHandler handler = (EventHandler)Events[TextChangeEvent];\n            if (handler != null)\n            {\n                handler(this, EventArgs.Empty);\n            }\n        }\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><p>执行之前保存在Events中的TextChangeEvent事件</p>',41),l={},a=(0,i(63243).Z)(l,[["render",function(e,n){return s}]])},63243:(e,n)=>{n.Z=(e,n)=>{const i=e.__vccOpts||e;for(const[e,s]of n)i[e]=s;return i}}}]);